'use client';
import { useEffect, useRef } from 'react';
import { motion } from 'framer-motion';

export default function CircularGallery({
  items,
  bend = 3,
  textColor = '#ffffff',
  borderRadius = 0.05,
  scrollSpeed = 2,
  scrollEase = 0.05,
}) {
  const containerRef = useRef(null);
  const trackRef = useRef(null);

  const defaults = [
    { image: `https://picsum.photos/seed/1/800/600?grayscale`, text: 'Bridge' },
    { image: `https://picsum.photos/seed/2/800/600?grayscale`, text: 'Desk Setup' },
    { image: `https://picsum.photos/seed/3/800/600?grayscale`, text: 'Waterfall' },
    { image: `https://picsum.photos/seed/4/800/600?grayscale`, text: 'Strawberries' },
    { image: `https://picsum.photos/seed/5/800/600?grayscale`, text: 'Deep Diving' },
    { image: `https://picsum.photos/seed/16/800/600?grayscale`, text: 'Train Track' },
    { image: `https://picsum.photos/seed/17/800/600?grayscale`, text: 'Santorini' },
    { image: `https://picsum.photos/seed/8/800/600?grayscale`, text: 'Blurry Lights' },
    { image: `https://picsum.photos/seed/9/800/600?grayscale`, text: 'New York' },
    { image: `https://picsum.photos/seed/10/800/600?grayscale`, text: 'Good Boy' },
    { image: `https://picsum.photos/seed/21/800/600?grayscale`, text: 'Coastline' },
    { image: `https://picsum.photos/seed/12/800/600?grayscale`, text: 'Palm Trees' },
  ];
  const data = items && items.length ? items : defaults;
  const loop = data.concat(data);

  useEffect(() => {
    let raf;
    const step = () => {
      const el = containerRef.current;
      const track = trackRef.current;
      if (el && track) {
        const delta = Math.max(0.3, scrollEase * 40) * scrollSpeed;
        el.scrollLeft += delta;
        const half = track.scrollWidth / 2;
        if (el.scrollLeft >= half) el.scrollLeft = 0;
      }
      raf = requestAnimationFrame(step);
    };
    raf = requestAnimationFrame(step);
    return () => cancelAnimationFrame(raf);
  }, [scrollEase, scrollSpeed]);

  return (
    <div ref={containerRef} className="w-full h-full overflow-x-auto no-scrollbar">
      <style jsx>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
      <div ref={trackRef} className="flex gap-6 py-2">
        {loop.map((item, idx) => {
          const angle = (idx % 3 === 0 ? -bend * 2 : idx % 3 === 1 ? 0 : bend * 2);
          const captionAngle = angle / 2;
          return (
            <motion.div
              key={`${item.text}-${idx}`}
              className="flex-none w-80 sm:w-96 lg:w-[30rem] relative p-4 rounded-3xl bg-slate-900/40 ring-1 ring-white/10"
              initial={{ opacity: 0, y: 24 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true, amount: 0.2 }}
              transition={{ duration: 0.4, delay: (idx % 12) * 0.03 }}
            >
              <div
                className="overflow-hidden shadow-xl"
                style={{ transform: `rotate(${angle}deg)`, borderRadius: `${borderRadius * 200}px` }}
              >
                <img
                  src={item.image}
                  alt={item.text}
                  className="w-full h-72 md:h-80 object-cover grayscale"
                />
              </div>
              <p
                className="mt-3 text-center text-sm md:text-base"
                style={{ color: textColor, transform: `rotate(${captionAngle}deg)` }}
              >
                {item.text}
              </p>
            </motion.div>
          );
        })}
      </div>
    </div>
  );
}
