import SectionTitle from "@/components/section-title";
import { motion } from "framer-motion";
import { useEffect, useRef, useState } from "react";

export default function AboutOurApps() {
    const sectionData = [
        {
            title: "Built to Innovate",
            description: " High-performance digital and AI solutions designed for future growth.",
            image: "https://raw.githubusercontent.com/prebuiltui/prebuiltui/main/assets/aboutSection/flashEmoji.png",
            className: "py-10 border-b border-slate-700 md:border-r md:border-b md:px-10 lg:border-b-0"
        },
        {
            title: "Crafted as Infrastructure",
            description: "Every solution is engineered as a foundation, not a feature.",
            image: "https://raw.githubusercontent.com/prebuiltui/prebuiltui/main/assets/aboutSection/colorsEmoji.png",
            className: "py-10 border-b border-slate-700 md:border-b md:px-10 lg:border-r lg:border-b-0"
        },
        {
            title: "Skilled Professionals",
            description: "Our team of experts ensures your business goals are achieved efficiently with a client-focused approach.",
            image: "https://raw.githubusercontent.com/prebuiltui/prebuiltui/main/assets/aboutSection/puzzelEmoji.png",
            className: "py-10 border-b border-slate-700 md:border-r md:border-b-0 md:px-10 lg:border-b-0"
        },
      
   
       
    ];
    const sliderRef = useRef(null);
    const [currentSlide, setCurrentSlide] = useState(0);
    const totalSlides = sectionData.length;
    const [stopScroll, setStopScroll] = useState(false);
    const cardData = sectionData; // alias for clarity with the provided snippet

    useEffect(() => {
        const el = sliderRef.current;
        if (!el) return;

        const id = setInterval(() => {
            setCurrentSlide((s) => (s + 1) % totalSlides);
        }, 3000);

        return () => clearInterval(id);
    }, [totalSlides]);
    return (
        <section className="flex flex-col items-center" id="about">
            <SectionTitle title="About Nexvity" description="Your partner in AI driven innovation, Software development, and UX design for modern businesses." />
            {/* Auto-playing card slider (single-slide viewport, transform-based) */}
            <div className="flex flex-col items-center w-full">
                <div className="w-full max-w-3xl overflow-hidden relative my-8">
                    <div
                        ref={sliderRef}
                        className="flex transition-transform duration-500 ease-in-out"
                        style={{ transform: `translateX(-${currentSlide * 100}%)` }}
                    >
               
               
                        {sectionData.map((item, i) => (
                            <div className="w-full flex-shrink-0 px-4" key={i}>
                                <div className="w-full min-h-[14rem] md:min-h-[16rem] lg:min-h-[18rem] p-6 rounded-lg bg-gradient-to-r from-white/5 to-transparent border border-white/5 flex flex-col items-center text-center justify-center gap-4">
                                    <img src={item.image} alt="" className="w-20 h-20 md:w-24 md:h-24 object-cover rounded mb-2" />
                                    <div className="">
                                        <h4 className="text-lg md:text-xl font-semibold text-slate-200 mb-2">{item.title}</h4>
                                        <p className="text-sm md:text-base text-slate-400 whitespace-normal leading-relaxed">{item.description}</p>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* dot indicators */}
                <div className="flex items-center mt-3 space-x-2" role="tablist" aria-label="Slider indicators">
                    {sectionData.map((_, i) => (
                        <button
                            key={i}
                            onClick={() => setCurrentSlide(i)}
                            aria-label={`Go to slide ${i + 1}`}
                            className={`w-3 h-3 rounded-full ${currentSlide === i ? 'bg-white' : 'bg-black/20'}`}
                        />
                    ))}
                </div>
            </div>

            {/* Marquee using provided animation code (cards, pause on hover, dynamic duration) */}
            <div className="overflow-hidden w-full relative max-w-6xl mx-auto my-8 mt-20" onMouseEnter={() => setStopScroll(true)} onMouseLeave={() => setStopScroll(false)}>
                <div className="marquee-inner flex w-fit" style={{ animationPlayState: stopScroll ? 'paused' : 'running', animationDuration: cardData.length * 2500 + 'ms' }}>
                    <div className="flex">
                        {[...cardData, ...cardData].map((card, index) => (
                            <div key={index} className="w-56 mx-4 h-[20rem] relative group hover:scale-95 transition-all duration-300">
                                <div className="w-full h-full flex flex-col items-center justify-center p-4 rounded-lg bg-gradient-to-r from-white/6 to-transparent border border-white/5 text-center">
                                    <h4 className="text-lg md:text-xl font-semibold text-white mb-2">{card.title}</h4>
                                    <p className="text-sm md:text-base text-slate-300 max-w-xs">{card.description}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
                
            </div>
           
            
        </section>
    );
}

// Styles: hide default scrollbar for a clean, sliding look + marquee
<style jsx>{`
.no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
.no-scrollbar::-webkit-scrollbar { display: none; }

.marquee-inner { animation: marqueeScroll linear infinite; animation-direction: normal; display: flex; gap: 1rem; align-items: center; white-space: nowrap; }
.marquee-inner:hover { animation-play-state: paused; }

@keyframes marqueeScroll {
    0% { transform: translateX(0%); }
    100% { transform: translateX(-50%); }
}
`}</style>
